1	import { quote, claim, type Item, type Incident } from "./claim-office.js";
2	
3	export type QuoteStep = {
4	  op: "quote";
5	  items: Item[];
6	};
7	
8	export type ClaimStep = {
9	  op: "claim";
10	  policy: number;
11	  incident: Incident;
12	};
13	
14	export type ScenarioStep = QuoteStep | ClaimStep;
15	
16	export type Scenario = {
17	  customer: { yearsWithMHPCO: number };
18	  steps: ScenarioStep[];
19	};
20	
21	export type StepResult = {
22	  premium?: number;
23	  payout?: number;
24	  remainingCap?: number;
25	};
26	
27	export type ScenarioResult = {
28	  results: StepResult[];
29	};
30	
31	const isQuoteStep = (step: ScenarioStep): step is QuoteStep => step.op === "quote";
32	
33	const runQuoteStep = (
34	  step: QuoteStep,
35	  priorSteps: ScenarioStep[],
36	  yearsWithMHPCO: number
37	): StepResult => {
38	  const isFollowUp = priorSteps.some(isQuoteStep);
39	  return { premium: quote(step.items, { yearsWithMHPCO, isFollowUp }) };
40	};
41	
42	const runClaimStep = (step: ClaimStep, steps: ScenarioStep[]): StepResult => {
43	  const policyStep = steps[step.policy];
44	  if (!isQuoteStep(policyStep)) {
45	    throw new Error(`Claim policy index ${step.policy} does not reference a quote step`);
46	  }
47	  return claim(policyStep.items, step.incident);
48	};
49	
50	export function runScenario(scenario: Scenario): ScenarioResult {
51	  const { yearsWithMHPCO } = scenario.customer;
52	  const { steps } = scenario;
53	  const results = steps.map((step, index): StepResult =>
54	    isQuoteStep(step)
55	      ? runQuoteStep(step, steps.slice(0, index), yearsWithMHPCO)
56	      : runClaimStep(step, steps)
57	  );
58	  return { results };
59	}
